import React, { useState } from 'react';

const App = () => {
  const [input1, setInput1] = useState('');
  const [input2, setInput2] = useState('');
  const [preview, setPreview] = useState('');

  const handleInput1Change = (e) => {
    setInput1(e.target.value);
    setPreview(e.target.value);
  };

  const handleInput2Change = (e) => {
    setInput2(e.target.value);
  };

  const handleSubmit = () => {
    setInput1('');
    setInput2('');
    setPreview('');
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white rounded-lg p-4 w-full max-w-md">
        <div className="flex justify-between mb-4">
          <input type="text" value={input1} onChange={handleInput1Change} className="w-1/2 p-2 border rounded-lg" placeholder="Type a message"/>
          <input type="text" value={input2} onChange={handleInput2Change} className="w-1/2 p-2 border rounded-lg" placeholder="Type a message"/>
        </div>
        <textarea value={preview} onChange={(e) => setPreview(e.target.value)} className="p-2 w-full border rounded-lg" placeholder="Preview"/>
        <button className="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded" onClick={handleSubmit}>Submit</button>
      </div>
    </div>
  );
};

export default App;
